// Define an asynchronous function to fetch product data.
async function fetchProducts() {
  try {
    // 1. Pause the function until the fetch() Promise resolves.
    // fetch() returns a Promise that resolves to the Response object.
    const response = await fetch(
      "https://mdn.github.io/learning-area/javascript/apis/fetching-data/can-store/products.json"
    );

    // 2. Check if the HTTP response was successful.
    if (!response.ok) {
      // If not, throw an error to be caught by the catch block.
      throw new Error(`HTTP error: ${response.status}`);
    }

    // 3. Pause the function again until the .json() Promise resolves.
    // .json() parses the response body as JSON and returns a new Promise.
    const data = await response.json();

    // 4. Once the data is available, log the name of the first product.
    console.log(data[0].name);
    return data; // The function's Promise resolves with this data.

  } catch (error) {
    // 5. If any error was thrown in the 'try' block, it gets caught here.
    console.error(`Could not get products: ${error}`);
  }
}

// Call the async function.
fetchProducts();

