// Use the 'require' syntax for CommonJS modules
const { MongoClient } = require('mongodb');

// Define the connection string for your MongoDB server
const uri = "mongodb://localhost:27017";

// Create a MongoClient instance
const client = new MongoClient(uri);

async function runMongoDBQuery() {
  try {
    // 1. Connect to the MongoDB cluster
    await client.connect();
    console.log("Connected to the database.");

    // 2. Specify the database and collection
    const database = client.db("myStore");
    const productsCollection = database.collection("products");

    // For demonstration, let's insert a sample product if it doesn't exist
    await productsCollection.updateOne(
      { name: "Wireless Mouse" },
      { $set: { name: "Wireless Mouse", price: 25.99, category: "Electronics" } },
      { upsert: true }
    );

    // 3. Define the query
    // This query will find all documents where the 'category' is 'Electronics'
    const query = { category: "Electronics" };

    // 4. Execute the query and get a cursor
    const cursor = productsCollection.find(query);

    // 5. Iterate over the results and print them
    console.log("\nFound the following electronic products:");
    const results = await cursor.toArray(); // Get results as an array
    if (results.length === 0) {
        console.log("No electronic products found.");
    } else {
        results.forEach(product => {
            console.log(`- Name: ${product.name}, Price: $${product.price}`);
        });
    }

  } catch (error) {
    console.error("An error occurred:", error);
  } finally {
    // 6. Ensure the client will close when you finish or an error occurs
    await client.close();
    console.log("\nDatabase connection closed.");
  }
}

// Run the function to execute the query
runMongoDBQuery();

